@startuml
title Facade 패턴(김동석)

skinparam classAttributeIconSize 0
skinparam shadowing false
skinparam linetype ortho

class ShapeMakerTest {
  void ShapeMakerFacadeTest()
}

class ShapeMaker {
  String drawAllShape()
}

interface Shape {
  String draw()
}

class Circle {
  String draw()
}

class Rectangle {
  String draw()
}

class Square {
  String draw()
}

ShapeMakerTest --> ShapeMaker
ShapeMaker --> Shape

Circle ..|> Shape
Rectangle ..|> Shape
Square ..|> Shape

@enduml
